ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?audience_rating WHERE {
  ?film a :Films .
  ?filmreviews a :FilmReviews .
  ?filmreviews p:hasFilm ?film .
  ?film p:title ?title .
  ?filmreviews p:audience_rating ?audience_rating .
} }
  component_2: { SELECT ?title ?critic_rating WHERE {
  ?film a :Films .
  ?filmreviews a :FilmReviews .
  ?filmreviews p:hasFilm ?film .
  ?film p:title ?title .
  ?filmreviews p:critic_rating ?critic_rating .
} }
  full: { SELECT ?title ?critic_rating ?audience_rating WHERE {
  ?film a :Films .
  ?filmreviews a :FilmReviews .
  ?filmreviews p:hasFilm ?film .
  ?film p:title ?title .
  ?filmreviews p:critic_rating ?critic_rating .
  ?filmreviews p:audience_rating ?audience_rating .
} }
}
